// Full request-to-worker-ready duration (needs follow-up publish-lifecycle customEvents
// carrying a shared deployment_id; not on main yet):
//   let requested = customEvents | where $__timeFilter(timestamp) | where name == "biller.publish_requested"
//     | project deployment_id = tostring(customDimensions.deployment_id), requested_at = timestamp;
//   let ready = customEvents | where $__timeFilter(timestamp) | where name == "biller.publish_ready"
//     | project deployment_id = tostring(customDimensions.deployment_id), ready_at = timestamp;
//   requested | join kind=inner ready on deployment_id
//   | extend duration_ms = 1000 * datetime_diff('second', ready_at, requested_at)
//   | summarize p50_ms = percentile(duration_ms, 50), p95_ms = percentile(duration_ms, 95) by bin(requested_at, 15m);
// Available now: worker processing duration from the publication histogram.
customMetrics
| where $__timeFilter(timestamp)
| where name == "ic.biller.publication.duration"
| summarize avg_ms = sum(valueSum) / sum(valueCount), max_ms = max(valueMax) by bin(timestamp, 15m)
| order by timestamp asc
